import {EventEmitter} from 'events';
import WSClient from './WSClient';
import RegistryClient from './RegistryClient';
import RegistrationRecord from './RegistrationRecord';

import parentLog from './log';
const log = parentLog.createChild('NotificationsDispatcher');


export type ErrCallback = (err?:Error)=>void;

// see also https://confluence.jibo.com/display/SER/Robot+Notifications
interface NotificationMessage {
    _id:string;
    skillId:string;
    payload:Payload;
    created:string;
}

interface Payload {
    name:string;
    payload:any;
}

const enum Status {
    Invalid,      // 0
    Connected,    // 1
    Disconnected  // 2
}

interface StatusMessage {
    status:Status;
}


export default class NotificationsDispatcher extends EventEmitter {

    static readonly instance = new NotificationsDispatcher();

    private _notificationsSocket:WSClient;
    private _statusSocket:WSClient;
    private _lastStatus:number;

    init(callback:ErrCallback) {
        RegistryClient.instance.getRecordByName('server',
            (err, record:RegistrationRecord) => {
                log.iferr(err, 'Error getting "server" service record');
                if(!err) {
                    this._setupSockets(`ws://${record.host}:${record.port}`);
                }
                log.info('Initialized');
                callback(err);
            });
    }

    private _processNotification = (message: NotificationMessage): void => {
        if (message && message.payload && message.payload.name) {
            log.info('emitting', message.payload.name);
            this.emit(message.payload.name, message.payload.payload);
        } else {
            log.warn('notification message being dropped here!', message);
        }
    }

    private _processStatus = (message: StatusMessage): void => {
        // NOTE: this intentionally ignores status of 0 ("Invalid")
        if (message && message.status) {
            // status reports stream out at 1Hz. only emit events on status changes.
            if (message.status !== this._lastStatus) {
                this._lastStatus = message.status;
                this.emit('StatusChanged', message.status);
                if (message.status === 1) {
                    this.emit('StatusConnected');
                }
                if (message.status === 2) {
                    this.emit('StatusDisconnected');
                }
            }
        } else {
            log.warn('status message being dropped here!', message);
        }
    }

    private _setupSockets(url) {
        if (!this._notificationsSocket) {
            let socketUrl = `${url}/server/notifications`;
            this._notificationsSocket = new WSClient(socketUrl);
            this._notificationsSocket.on('open', () => log.debug('notification socket open'));
            this._notificationsSocket.on('error', (err) => log.warn('notification socket error', err));
            this._notificationsSocket.on('message', this._processNotification);
        }
        if (!this._statusSocket) {
            let socketUrl = `${url}/server/notifications/status`;
            this._statusSocket = new WSClient(socketUrl);
            this._statusSocket.on('open', (err) => log.debug('status socket open'));
            this._statusSocket.on('error', (err) => log.warn('status socket error', err));
            this._statusSocket.on('message', this._processStatus);
        }
    }
}
