import {EventEmitter} from 'events';
import http = require('http');
import {RequestOptions, ClientRequest, ClientResponse} from "http";

import parentLog from './log';
const log = parentLog.createChild('HTTPClient');

/**
 * HTTP Client
 * @class HTTPClient
 * @extends EventEmitter
 * @param {String} host Registry host
 * @param {String} port Registry port
 */
class HTTPClient extends EventEmitter {

    /**
     * Constructor
     */
    constructor(public host:string, public port:number) {
        super();

        /**
         * Host
         * @name HTTPClient#host
         * @type {String}
         */

        /**
         * Port
         * @name HTTPClient#port
         * @type {Number}
         */
    }

    /**
     * Send a request.
     * @method HTTPClient#sendRequest
     * @param {String} method
     * @param {String} path
     * @param {String} body
     * @param {Function} callback
     */
    sendRequest(method:string, path:string, body:string, callback:(error:Error, response?:any) => void):void {
        let options:RequestOptions = {
            host: this.host,
            port: this.port,
            path: path,
            method: method,
            headers: {
                "Content-Type" : "application/json",
                "Content-Length": body.length
            }
        };
        let request:ClientRequest = http.request(options, (response:ClientResponse) => {
            response.setEncoding('utf8');
            let data = '';
            response.on('data', (chunk:string) => {
                data += chunk.toString();
            });
            response.on('end', () => {
                let err;
                let json;
                if (data.length > 0) {
                    try {
                        json = JSON.parse(data);
                    } catch(e) {
                        if (data.length < 500) {
                            log.error('could not parse JSON from request', `${this.host}:${this.port}${path}`, data);
                        } else {
                            log.error('could not parse JSON from request', `${this.host}:${this.port}${path}`);
                        }
                        err = e;
                    }
                }
                if (err) {
                    callback(err);
                } else {
                    if (response.statusCode < 200 || response.statusCode > 299) {
                        err = new Error('HTTP Error Code '+response.statusCode+' '+response.statusMessage);
                    }
                    callback(err, json);
                }
            });
        });

        request.on('error', (err:Error) => {
            callback(new Error('problem with request: ' + err.message));
        });
        request.write(body);
        request.end();

    }

    /**
     * Post JSON data.
     * @method HTTPClient#postJSON
     * @param {String} path The API path. Ex. /media/recording/start
     * @param {Object} json JSON payload
     * @param {Function} callback
     */
    postJSON( path:string, json:any, callback:(error:Error, response?:any) => void):void {
        this.sendRequest('post', path, JSON.stringify( json ), callback );
    }

    /**
     * Get JSON from request.
     * @method HTTPClient#getJSON
     * @param {String} path The API path. Ex. /media/recording/start
     * @param {Object} json JSON payload
     * @param {Function} callback
     */
    getJSON( path:string, json:any, callback:(error:Error, response?:any) => void):void {
        this.sendRequest('get', path, JSON.stringify( json ), callback );
    }

    get(path:string, callback:(error:Error, response?:any) => void):void {
        let request:ClientRequest = http.get('http://' + this.host + ':' + this.port + path, (response:ClientResponse) => {
            let data = '';
            response.on('data', (chunk:string) => {
                data += chunk.toString();
            });
            response.on('end', () => {
                callback(null, JSON.parse(data));
            });
        });

        request.on('error', (e) => {
            callback(new Error(`Got error: ${e.message}`));
        });
    }
}

export default HTTPClient;
