import HTTPClient from './HTTPClient';
import http = require('http');
import {RequestOptions, ClientRequest, ClientResponse} from "http";
import parentLog from './log';

const log = parentLog.createChild('SystemManager');

export class SingletonEnforcer{}

class SystemManagerClient extends HTTPClient {

    public static NAME:string = 'system-manager';

    private static _instance:SystemManagerClient;

    public static createInstance(host:string, port:number):SystemManagerClient {
        return SystemManagerClient._instance ||
            new SystemManagerClient(new SingletonEnforcer(), host, port);
    }

    public static get instance():SystemManagerClient {
        return SystemManagerClient._instance;
    }

    constructor(enforcer:SingletonEnforcer, public host:string, public port:number) {
        super(host, port);
        log.debug('constructor', host, port);
        SystemManagerClient._instance = this;
    }

    get(path:string, callback:(error:Error, response?:any) => void):void {
        const url = `http://${this.host}:${this.port}${path}`;
        log.debug('get', url);
        let request:ClientRequest = http.get(url, (response:ClientResponse) => {
            let data = '';
            response.on('data', (chunk:string) => {
                data += chunk.toString();
            });
            response.on('end', () => {
                if (response.statusCode === 200) {
                    log.debug('got', url);
                    callback(null, JSON.parse(data));
                }
                else {
                    // failure if anything else
                    let msg:string = 'System Manager is unavailable';
                    if (response.statusMessage !== undefined && response.statusMessage !== "") {
                        msg = response.statusMessage;
                    }
                    log.warn(msg);
                    callback(new Error(msg));
                }
            });
        });

        request.on('error', (e) => {
            log.warn(`Error getting ${url}`, e);
            callback(new Error(`Got error: ${e.message}`));
        });
    }

    sendRequest(method:string, path:string, body:string, callback:(error:Error, response?:any) => void):void {
        let options:RequestOptions = {
            host: this.host,
            port: this.port,
            path: path,
            method: method,
            headers: {
                "Content-Type" : "application/json",
                "Content-Length": body.length
            }
        };
        let request:ClientRequest = http.request(options, (response:ClientResponse) => {
            response.setEncoding('utf8');
            let data = '';
            response.on('data', (chunk:string) => {
                data += chunk.toString();
            });
            response.on('end', () => {
                if (response.statusCode === 204) {
                    callback(null); // success! no content
                }
                else if (response.statusCode === 200) {
                    callback(null, JSON.parse(data));
                }
                else {
                    // failure if anything else
                    let msg:string = 'System Manager is unavailable';
                    if (response.statusMessage !== undefined && response.statusMessage !== "") {
                        msg = response.statusMessage;
                    }
                    log.warn(msg);
                    callback(new Error(msg));
                }
            });
        });

        request.on('error', (e:Error) => {
            log.warn(`Problem with ${method} request to ${path}`, e);
            callback(new Error('Problem with request: ' + e.message));
        });

        request.write(body);
        request.end();
    }

    getVersion(callback:(error:Error, response?:any) => void):void {
        this.sendRequest('GET', '/version', "", callback);
    }

    list(callback: (error:Error, skills:Array<SkillRecord>) => void):void {
        this.get('/skill/list', (error:Error, skills:{skills:Array<SkillRecord>}) => {
            callback(error, skills ? skills.skills : null);
        });
    }

    getSkillRecordByName(name:string, callback: (error:Error, skill?:SkillRecord) => void):void {
        this.list((error:Error, skills:Array<SkillRecord>) => {
            if(error) {
                return callback(error);
            }
            for(let i:number = 0; i < skills.length; i++) {
                if(skills[i].name === name) {
                    return callback(null, skills[i]);
                }
            }
            return callback(new Error(`Could not find skill with name ${name}`));
        });
    }

    launch(name:string, callback:(error:Error) => void):void {
        let body:string = JSON.stringify({
            name: name,
            context: '{}'
        });
        this.sendRequest('POST', '/skill/launch', body, callback);
    }

    terminate(name:string, callback:(error:Error) => void):void {
        let body:string = JSON.stringify({
            name: name
        });
        this.sendRequest('POST', '/skill/terminate', body, callback);
    }

    getMode(callback:(error:Error, mode?:string) => void) {
        this.get('/mode', (error:Error, data:{mode:string}) => {
            if(error) {
                return callback(error);
            }
            callback(null, data.mode);
        });
    }

    syncTime(callback:(error:Error, response?:any) => void):void {
        this.sendRequest('POST', '/time/synchronize', "", callback);
    }
    
    getTimeZone(callback:(error, timezone?:string) => void) {
        this.sendRequest('GET', '/time/zone', "", (err, response) => {
            if (err) {
                return callback(err);
            }
            callback(response ? response.timezone : null);
        });
    }

    setTimeZone(zone:string, callback:(error, response?:any) => void) {

        if(!zone) {
            callback("No zone given");
            return;
        }

        let body = "";
        try {
            body = JSON.stringify({ timezone: zone });
        }
        catch(e) {
            callback("Timezone request is not valid JSON");
            return;
        }

        this.sendRequest('POST', '/time/zone', body, callback);
    }

    getCredentials(callback) {
        this.get('/credentials',(error:Error, data:any) => {
            if(error || !data) {
                return callback((!error ? new Error("No credentials set") : error), null);
            }

            if (!data.hasOwnProperty("accessKeyId") || data["accessKeyId"].length === 0) {
                return callback(new Error("No credentials: accessKeyId is not set."));
            }

            if (!data.hasOwnProperty("secretAccessKey") || data["secretAccessKey"].length === 0) {
                return callback(new Error("No credentials: secretAccessKey is not set."));
            }

            if (!data.hasOwnProperty("region") || data["region"].length === 0) {
                return callback(new Error("No credentials: region is not set."));
            }

            callback(null, data);
        });
    }


    ///
    /// Wifi-related APIs
    ///
    sendWifiRequest(method:string, path:string, body:string, callback:WifiCallback):void {
        this.sendRequest(method, path, body, (error:Error, res?:any)=> {
            // wifi-related data always comes back as "response" property
            callback(error, (res ? res.response : null));
        });
    }

    addNetwork(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "ADD_NETWORK"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    removeNetwork(networkId:string, callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "REMOVE_NETWORK " + networkId
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    saveConfig(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SAVE_CONFIG"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    disconnect(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "DISCONNECT"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    signalPoll(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SIGNAL_POLL"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    setNetwork(networkData:string, callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SET_NETWORK " + networkData
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    selectNetwork(networkId:string, callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SELECT_NETWORK " + networkId
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    enableNetwork(networkId:string, callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "ENABLE_NETWORK " + networkId
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    setInterface(interfaceData:InterfaceData, callback:WifiCallback):void {
        let body:string = JSON.stringify({
            interface: interfaceData
        });
        this.sendWifiRequest('POST', '/wifi/interface', body, callback);
    }

    getInterface(callback:WifiCallback) {
        this.get('/wifi/interface', (error:Error, data:{interface:InterfaceData}) => {
            if(error) {
                return callback(error);
            }
            callback(null, data.interface);
        });
    }

    listNetworks(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "LIST_NETWORKS"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    wifiStatus(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "STATUS-VERBOSE"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    scan(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SCAN"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }

    scanResults(callback:WifiCallback):void {
        let body:string = JSON.stringify({
            command: "SCAN_RESULTS"
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, callback);
    }
    
    /**
     * Does background scanning for better networks/access points to connect to.
     * @param strengthThreshold db of current connection signal strength
     * @param weakRescanDelay seconds between scans if strength is weaker than strengthThreshold
     * @param strongRescanDelay seconds between if strength is stronger than strengthThreshold
     */
    bgScan(weakRescanDelay:number, strengthThreshold:number, strongRescanDelay:number, callback:WifiCallback):void {
        //set up bgscan command, doing a fast conversion to integers using binary OR
        let body:string = JSON.stringify({
            command: `SET bgscan "simple:${weakRescanDelay | 0}:${strengthThreshold | 0}:${strongRescanDelay | 0}"`
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, (err) => {
            if (err) {
                return callback(err);
            }
            //automatically follow with a save, so that this method can be used on its own
            this.saveConfig(callback);
        });
    }
    
    /**
     * Does active scanning automatically. Should replace most usage of scan().
     * @param scanDelay seconds between scans
     */
    activeAutoScan(rescanDelay:number, callback:WifiCallback):void {
        //set up autoscan command, doing a fast conversion to integer using binary OR
        let body:string = JSON.stringify({
            command: `AUTOSCAN periodic:${rescanDelay | 0}`
        });
        this.sendWifiRequest('POST', '/wifi/wpa', body, (err) => {
            if (err) {
                return callback(err);
            }
            //automatically follow with a save, so that this method can be used on its own
            this.saveConfig(callback);
        });
    }

    getSemanticStorage(callback:SemanticStorageCallback):void {
        this.get('/storage/semantic', (error:Error, data?:SemanticStorageData) => {
            if(error) {
                return callback(error);
            }
            callback(null, data);
        });
    }
}


export interface SkillRecord {
    name:string;
    path:string;
    running?:boolean;
    lastStartTime?:{time_since_epoch:{count:number}};
}

export interface InterfaceData {
    method:string;
    address:string;
    network:string;
    netmask:string;
    broadcast:string;
    gateway:string;
    dns:string;
}

export declare type WifiCallback = (err:Error, response?:any) => void;

export interface SemanticStorageData {
    usage:SemanticStorageUsageRecord[];
}

export interface SemanticStorageUsageRecord {
    type:string;
    path:string;
    size:number;
}

export declare type SemanticStorageCallback = (err:Error, storage?:SemanticStorageData) => void;

export default SystemManagerClient;
