import RemoteClient from './RemoteClient';
import {EventEmitter} from 'events';

class ClientRemoteObject extends EventEmitter {

    protected instanceId:number;

    constructor(protected client:RemoteClient, protected options:{instanceId:number}) {
        super();
        client.instances.set(options.instanceId, this);
        this.instanceId = options.instanceId;
    }

    public async sendMessage<T>(methodName:string, args?:any[], sendAndForget:boolean = false):Promise<T> {
        return await this.client.sendMessage<T>(this.instanceId, methodName, args, sendAndForget);
    }


    public destroy() {
        this.client.instances.delete(this.instanceId);
    }
}


export default ClientRemoteObject;
