import {EventEmitter} from "events";
import {PromiseUtils} from 'jibo-cai-utils';
import parentLog from './log';
import WebSocket = require('ws');

const log = parentLog.createChild('WSClient');
//const MAX_QUEUE_SIZE = 10;

declare type Resolve = (value?: boolean | PromiseLike<boolean>) => void;

