/**
 * HTTP WebSocket Client
 * @class HTTPWSClient
 * @extends EventEmitter
 * @param {String} host
 */
export default class HTTPWSClient extends EventEmitter {

    /**
     * The socket connection.
     * @name HTTPWSClient#socket
     * @type {WebSocket}
     */
    public socket: WebSocket;

    private _isReconnecting: boolean = false;
    //private _messageQueue: QueuedMessage[] = [];

    constructor(public host: string) {
        super();
        this._connect();
    }

    /**
     * Send data.
     * @method HTTPWSClient#send
     * @param {String|Object} json Either pre-serialzed or raw data object
     * @returns {Promise<boolean>} Whether the send succeeded
     */
    // Generally, using reject with Promise<void> is prefered to a boolean
    // Promise, but since the legacy of this method is fire-and-forget, we
    // don't want to kick out unhandled promise rejections, so we instead
    // resolve with a boolean, false on fail
    public send(json: string | Object): Promise<boolean> {
        return new Promise<boolean>(async (resolve) => {
            // Fail fast if we can't serialize the object
            let payload: string;
            if (typeof json === 'string') {
                payload = json;
            } else {
                try {
                    payload = JSON.stringify(json);
                } catch (err) {
                    // Log stringify failures at error level, since there's likely
                    // nothing the caller can do to recover gracefully, and it's
                    // likely a logic error in the caller's code (object too
                    // complex - will need a code change)
                    log.error('Error stringifying json param:', err);
                    return resolve(false);
                }
            }
            await this._sendMessage(payload, resolve);
            // If the socket hasn't been created, or isn't open, queue the
            // message for sending upon reconnection
            // if (!this.socket || this.socket.readyState !== WebSocket.OPEN) {
            //     // Log this situation at info level, since we'll be retrying
            //     // upon connection
            //     if (!this.socket) {
            //         log.info('Socket doesn\'t exist on send; queuing for later');
            //     } else {
            //         log.info(`Socket isn't open on send; queuing for later; status: ${this.socket.readyState}`);
            //     }
            //     // Queue the message for sending later, including the resolve
            //     // method so we can return the success/fail
            //     // If we have more than the maximum messages, resolve the
            //     // oldest one with a failure
            //     // if (this._messageQueue.push({payload, resolve}) > MAX_QUEUE_SIZE) {
            //     //     log.warn('Too many messages on queue; failing the oldest');
            //     //     this._messageQueue.shift().resolve(false);
            //     // }
            //     // Don't resolve yet; leave the caller waiting in anticipation
            //     // until we process the queue in onOpen
            //     // return
            // }
            // The socket exists and is open: send the message
            // await this._sendMessage(payload, resolve);
        });
    }

    private _connect = (): void => {
        log.debug('connect');
        this.socket = new WebSocket(this.host, <any>{perMessageDeflate: false});
        this.socket.on('error', this._onError);
        this.socket.on('close', this._onClose);
        this.socket.on('message', this._onMessage);
        this.socket.on('open', this._onOpen);
    }

    /**
     * Called when there is an error to try reconnect
     */
    private _onStartReconnect = (): void => {
        this._isReconnecting = true;
        this.socket.removeAllListeners();
        this.socket = null;
        setTimeout(this._connect, 1000);
    }

    private _onError = (err: Error): void => {
        log.warn('socket error', err);
        this._onStartReconnect();
    }

    private _onClose = (code: number, message: string): void => {
        log.warn(`socket ${this.host} closed`, code, message);
        this.emit('close');
        this._onStartReconnect();
    }

    private _onMessage = (data: string): void => {
        let command: any;
        try {
            // TOFIX: Take this out when the platform service
            // fixes on their end; really should throw an error when we receive NaN.
            command = JSON.parse(data.replace(/\bNaN\b/g, "0"));
        } catch(err) {
            const r: RegExp = /at position (\d+)/g;
            const result: RegExpExecArray = r.exec(err.message);
            if (data.length < 500) {
                if (result) {
                    const pos: number = parseInt(result[1]);
                    log.error(`Invalid JSON sent to jibo client on host ${this.host} at position ${pos}`, data);
                } else {
                    log.error('Invalid JSON sent to jibo client on host ' + this.host, data);
                }
            } else {
                if (result) {
                    const padding = 250;
                    let pos: number = parseInt(result[1]);
                    data = data.substr(Math.max(0, pos - padding), Math.min(data.length - 1, pos + padding));
                    if (pos > padding) {
                        pos = padding;
                    }
                    log.error('Invalid JSON sent to jibo client on host' + this.host + ' at position ' + pos  + ' of snippet', data);
                } else {
                    log.error('Invalid JSON sent to jibo client on host ' + this.host);
                }

            }
            // this.emit('error','json ' + e, data);
        }
        //if the JSON parse succeeded, send the message
        //if this is inside the try, then if someone has an error up the chain we swallow it
        //and pretend that it is bad JSON
        if (command) {
            this.emit('message', command);
        }
    }

    private _onOpen = async (): Promise<void> => {
        this.emit('open');
        if (this._isReconnecting) {
            this._isReconnecting = false;
            this.emit('reopen');
        }
        // Process any waiting messages
        // let message: QueuedMessage;
        // while (message = this._messageQueue.shift()) {
        //     this._sendMessage(message.payload, message.resolve);
        // }
    }

    private async _sendMessage(
        payload: string,
        resolve: Resolve,
    ): Promise<void> {
        try {
            await PromiseUtils.promisify(cb => this.socket.send(payload, cb));
            resolve(true);
        } catch (err) {
            // Log message-sending failures at warn level, since the Promise
            // allows graceful recovery by the caller (e.g. retry loop) and
            // it's an expected runtime situation (e.g. service temporarily
            // down)
            if (!this.socket) {
                log.warn('Socket doesn\'t exist on send', err);
            } else {
                log.warn(`Socket isn't open on send; readState: ${this.socket.readyState}`, err);
            }
            resolve(false);
        }
    }
}
